questionsScript:
[
  {
    "id": 1,
    "question": "Lo stato dell'ODV indica che l'ordine di vendita è uscito?",
    "type": "boolean",
    "variable": "Stato ODV",
    "options": [
      {
        "label": "Sì, ODV Uscito (0)",
        "value": 0,
        "nextQuestionId": 2
      },
      {
        "label": "No, ODV Non Uscito (1)",
        "value": 1,
        "nextQuestionId": 3
      }
    ]
  },
  {
    "id": 2,
    "question": "Desideri procedere con l'invio immediato degli allarmi marketing?",
    "type": "boolean",
    "variable": "Autorizzazione Invio Immediato",
    "options": [
      {
        "label": "Sì, invia gli allarmi",
        "value": true,
        "decision": "Inviare immediatamente gli allarmi flyer marketing. Distribuire i materiali promozionali a tutti i canali designati e registrare il timestamp di invio nel sistema."
      },
      {
        "label": "No, rinvia l'invio",
        "value": false,
        "decision": "Posticipare l'invio degli allarmi flyer marketing. Mantenere l'ODV nella coda di elaborazione per una revisione successiva."
      }
    ]
  },
  {
    "id": 3,
    "question": "Vuoi impostare una notifica automatica per quando l'ODV uscirà?",
    "type": "boolean",
    "variable": "Attivazione Notifica Automatica",
    "options": [
      {
        "label": "Sì, attiva notifica automatica",
        "value": true,
        "decision": "Mettere in pausa l'invio degli allarmi flyer marketing e configurare un trigger automatico. Quando lo stato ODV cambierà a 'Uscito (0)', il sistema invierà automaticamente gli allarmi e i materiali marketing senza ulteriore intervento manuale."
      },
      {
        "label": "No, non attivare notifica",
        "value": false,
        "decision": "Sospendere l'invio degli allarmi flyer marketing. L'ODV rimane in attesa. Revisione manuale richiesta prima di qualsiasi distribuzione futura."
      }
    ]
  }
]
